/// Check if image processing is needed by examining OCR and image extraction settings.
///
/// Returns `true` if either OCR is enabled or image extraction is configured,
/// indicating that image decompression and processing should occur.
/// Returns `false` if both are disabled, allowing optimization to skip unnecessary
/// image decompression for text-only extraction workflows.
///
/// # Optimization Impact
/// For text-only extractions (no OCR, no image extraction), skipping image
/// decompression can improve CPU utilization by 5-10% by avoiding wasteful
/// image I/O and processing when results won't be used.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_extraction_config_needs_image_processing(
    this: *const kreuzberg::ExtractionConfig,
) -> i32 {
    clear_last_error();
    if this.is_null() {
        set_last_error(1, "Null pointer passed for self");
        return 0;
    }
    // SAFETY: null check above guarantees this is a valid pointer.
    let obj = unsafe { &*this };

    let result = obj.needs_image_processing();
    if result {
        1
    } else {
        0
    }
}

