fn get_ffi_runtime() -> &'static tokio::runtime::Runtime {
    use std::sync::OnceLock;
    static RUNTIME: OnceLock<tokio::runtime::Runtime> = OnceLock::new();
    RUNTIME.get_or_init(|| tokio::runtime::Runtime::new().expect("Failed to create tokio runtime"))
}

/// Extract content from a byte array.
///
/// This is the main entry point for in-memory extraction. It performs the following steps:
/// 1. Validate MIME type
/// 2. Handle legacy format conversion if needed
/// 3. Select appropriate extractor from registry
/// 4. Extract content
/// 5. Run post-processing pipeline
///
/// # Arguments
///
/// * `content` - The byte array to extract
/// * `mime_type` - MIME type of the content
/// * `config` - Extraction configuration
///
/// # Returns
///
/// An `ExtractionResult` containing the extracted content and metadata.
///
/// # Errors
///
/// Returns `KreuzbergError::Validation` if MIME type is invalid.
/// Returns `KreuzbergError::UnsupportedFormat` if MIME type is not supported.
///
/// # Example
///
/// ```rust,no_run
/// use kreuzberg::core::extractor::extract_bytes;
/// use kreuzberg::core::config::ExtractionConfig;
///
/// let config = ExtractionConfig::default();
/// let bytes = b"Hello, world!";
/// let result = extract_bytes(bytes, "text/plain", &config).await?;
/// println!("Content: {}", result.content);
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_extract_bytes(
    content: *const u8,
    content_len: usize,
    mime_type: *const std::ffi::c_char,
    config: *const kreuzberg::ExtractionConfig,
) -> *mut kreuzberg::ExtractionResult {
    clear_last_error();
    if content.is_null() && content_len > 0 {
        set_last_error(1, "Null pointer passed for parameter 'content'");
        return std::ptr::null_mut();
    }
    // SAFETY: when content is null, content_len is 0 (checked above), so we use an empty slice; otherwise data is valid for len elements.
    let content_rs = if content.is_null() {
        Vec::new()
    } else {
        unsafe { std::slice::from_raw_parts(content, content_len) }.to_vec()
    };
    if mime_type.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'mime_type'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees mime_type is a valid pointer; string is valid UTF-8 from caller.
    let mime_type_rs = match unsafe { CStr::from_ptr(mime_type) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'mime_type'");
            return std::ptr::null_mut();
        }
    };
    if config.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'config'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees config is a valid pointer.
    let config_rs = unsafe { &*config };
    let result =
        get_ffi_runtime().block_on(async { kreuzberg::extract_bytes(&content_rs, &mime_type_rs, &config_rs).await });
    match result {
        Ok(val) => Box::into_raw(Box::new(val)),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

/// Extract content from a file.
///
/// This is the main entry point for file-based extraction. It performs the following steps:
/// 1. Check cache for existing result (if caching enabled)
/// 2. Detect or validate MIME type
/// 3. Select appropriate extractor from registry
/// 4. Extract content
/// 5. Run post-processing pipeline
/// 6. Store result in cache (if caching enabled)
///
/// # Arguments
///
/// * `path` - Path to the file to extract
/// * `mime_type` - Optional MIME type override. If None, will be auto-detected
/// * `config` - Extraction configuration
///
/// # Returns
///
/// An `ExtractionResult` containing the extracted content and metadata.
///
/// # Errors
///
/// Returns `KreuzbergError::Io` if the file doesn't exist (NotFound) or for other file I/O errors.
/// Returns `KreuzbergError::UnsupportedFormat` if MIME type is not supported.
///
/// # Example
///
/// ```rust,no_run
/// use kreuzberg::core::extractor::extract_file;
/// use kreuzberg::core::config::ExtractionConfig;
///
/// let config = ExtractionConfig::default();
/// let result = extract_file("document.pdf", None, &config).await?;
/// println!("Content: {}", result.content);
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_extract_file(
    path: *const std::ffi::c_char,
    mime_type: *const std::ffi::c_char,
    config: *const kreuzberg::ExtractionConfig,
) -> *mut kreuzberg::ExtractionResult {
    clear_last_error();
    if path.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'path'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees path is a valid pointer; string is valid UTF-8 from caller.
    let path_rs = match unsafe { CStr::from_ptr(path) }.to_str() {
        Ok(s) => std::path::PathBuf::from(s),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'path'");
            return std::ptr::null_mut();
        }
    };
    let mime_type_rs = if mime_type.is_null() {
        None
    } else {
        // SAFETY: null check above guarantees mime_type is a valid pointer; string is valid UTF-8 from caller.
        match unsafe { CStr::from_ptr(mime_type) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'mime_type'");
                return std::ptr::null_mut();
            }
        }
    };
    if config.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'config'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees config is a valid pointer.
    let config_rs = unsafe { &*config };
    let result = get_ffi_runtime()
        .block_on(async { kreuzberg::extract_file(path_rs, mime_type_rs.as_deref(), &config_rs).await });
    match result {
        Ok(val) => Box::into_raw(Box::new(val)),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

